  ('Emergent', 'emergent', 'AI-powered full-stack builder using natural language.', 'AI-powered full-stack builder using natural language. Best for: suits rapid prototyping of custom apps without design skills.. Pricing: Not specified (AI-focused) emergent.', 'Website Creation', 'unknown', 'medium', 4.5, 'https://emergent.sh', false),
  ('Wix', 'wix', 'Drag-and-drop for beginners, including e-commerce.', 'Drag-and-drop for beginners, including e-commerce. Best for: best for quick small biz sites, stores, bookings.. Pricing: Free; Core $16/mo; Business $27/mo.', 'Website Creation', 'freemium', 'low', 4.5, 'https://wix.com', false),
