INSERT INTO tools (name, slug, short_description, long_description, category, pricing_model, budget_level, rating, website_link, is_sponsored) VALUES
  ('Metabase', 'metabase', 'Visual charts atop databases; self-service BI for', 'Visual charts atop databases; self-service BI for. Open-source BI with SQL-free question builder, 40+ chart types, dashboard embedding, row-level security (Pro+), SSO/SAML (Enterprise), supports 15+ databases, admin audit logs, scheduled reports, public', 'Analytics', 'freemium', 'high', 4.5, '', false),
  ('Power BI', 'power-bi', 'Drag-drop reports from any source; enterprise', 'Drag-drop reports from any source; enterprise. Microsoft''s no-code BI with Power Query ETL, 100+ connectors (Excel, SQL, Salesforce), AI visuals (key influencers, decomposition trees), paginated reports, dataflows, gateway for on-prem, row-level security, mobile', 'Analytics', 'freemium', 'low', 4.5, '', false),
  ('Google Looker Studio', 'google-looker-studio', 'Google ecosystem BI; real-time marketing', 'Google ecosystem BI; real-time marketing. Formerly Data Studio; BigQuery-optimized with community connectors, blended data, calculated fields, cross-filtering, drill-downs, themes, real-time collaboration, 500+ templates, date range controls, button', 'Analytics', 'free', 'low', 4.5, '', false),
  ('Superset', 'superset', 'Modern BI/SQL IDE; advanced', 'Modern BI/SQL IDE; advanced. Airbnb-originated petabyte-scale BI; SQLAlchemy 50+ DB connectors, semantic layer (virtual metrics/datasets), 40+ viz types, dashboard filters, Jinja templating, CSV/JSON support, role-based access technology.amis+1', 'Analytics', 'free', 'low', 4.5, '', false),
  ('Index', 'index', 'AI natural language queries; instant charts for SaaS', 'AI natural language queries; instant charts for SaaS. IndexAI converts plain English to SQL/charts with guardrails against costly queries, dashboard sharing, saved questions, unified data sources, revenue metrics focus', 'Analytics', 'paid', 'medium', 4.5, '', false),
  ('ChartPixel', 'chartpixel', 'AI data cleaning/visuals; auto-charts for', 'AI data cleaning/visuals; auto-charts for. AI-powered with real-time processing, customizable dashboards, predictive analytics, ML integration, data import/export, geospatial analysis, natural language query, custom alerts, automated', 'Analytics', 'usage-based', 'medium', 4.5, '', false),
  ('Knack', 'knack', 'No-code app analytics; custom database', 'No-code app analytics; custom database. Database app platform with built-in reporting/visualization, trend identification, real-time performance monitoring, actionable insights without IT', 'Analytics', 'paid', 'medium', 4.5, '', false),
  ('Grafana', 'grafana', 'Time-series dashboards; monitoring/IoT', 'Time-series dashboards; monitoring/IoT. No-code query builder evolution to queryless investigations, 100+ plugins, Loki/Prometheus integration, alerting, annotations, transformations, Explore mode for ad-hoc', 'Analytics', 'freemium', 'low', 4.5, '', false),
  ('KNIME', 'knime', 'Visual data science workflows; ML', 'Visual data science workflows; ML. Drag-drop nodes for ETL/ML, 300+ connectors, Python/R integration, workflow sharing, big data processing (Spark), collaborative', 'Analytics', 'free', 'low', 4.5, '', false),
  ('Graphite Note', 'graphite-note', 'No-code predictive analytics; AutoML', 'No-code predictive analytics; AutoML. Automated ML models, prescriptive actions, time-series forecasting, business-ready predictions without data science', 'Analytics', 'usage-based', 'medium', 4.5, '', false),
  ('Livedocs', 'livedocs', 'Interactive AI charts; real-time', 'Interactive AI charts; real-time. AI-driven interactive visualizations, real-time data exploration, collaborative reporting for', 'Analytics', 'paid', 'low', 4.5, '', false),
  ('ChartBlocks', 'chartblocks', 'Live chart automation; API/spreadsheet', 'Live chart automation; API/spreadsheet. Embeddable live charts, real-time data feeds, API connectors, scheduled refreshes, responsive', 'Analytics', 'freemium', 'medium', 4.5, '', false),
  ('Querio', 'querio', 'Natural language agentic notebooks; plain English SQL', 'Natural language agentic notebooks; plain English SQL. Agentic notebooks translating business questions to SQL, enterprise-grade security, scalable', 'Analytics', 'enterprise', 'low', 4.5, '', false),
  ('Apache Zeppelin', 'apache-zeppelin', 'Multi-language notebooks; Spark/SQL', 'Multi-language notebooks; Spark/SQL. Web-based notebook with Spark/Flink/SQL interpreters, dynamic forms, collaborative', 'Analytics', 'free', 'low', 4.5, '', false),
  ('BlazeSQL', 'blazesql', 'AI SQL generation + viz; natural language', 'AI SQL generation + viz; natural language. Chat-to-SQL with visualization, database connections, query optimization, non-technical', 'Analytics', 'usage-based', 'medium', 4.5, '', false),
  ('Luminary', 'luminary', 'AI conversational analytics; chat', 'AI conversational analytics; chat. Chat interface for data analysis, marketing/sales insights, natural language', 'Analytics', 'paid', 'medium', 4.5, '', false),
  ('Evidence', 'evidence', 'Markdown-based reports; SQL automated', 'Markdown-based reports; SQL automated. Site generator from Markdown/SQL, automated charts, public dashboards, version control', 'Analytics', 'free', 'low', 4.5, '', false),
  ('Lightdash', 'lightdash', 'dbt + LookML explorer; modern warehouse', 'dbt + LookML explorer; modern warehouse. dbt integration, semantic layer, LookML explorer, YAML models, warehouse-native', 'Analytics', 'freemium', 'medium', 4.5, '', false),
  ('Matomo', 'matomo', 'Privacy-first web analytics; GDPR GA', 'Privacy-first web analytics; GDPR GA. 100+ reports, heatmaps, A/B testing, form analytics, e-commerce tracking, API, plugins', 'Analytics', 'freemium', 'low', 4.5, '', false),
  ('Shynet', 'shynet', 'Cookie-less detailed analytics; lightweight', 'Cookie-less detailed analytics; lightweight. Self-hosted, no cookies/PII, unique visitor tracking, real-time dashboard, simple embed', 'Analytics', 'free', 'low', 4.5, '', false),
  ('Umami', 'umami', 'Simple privacy-first dashboards; real-time', 'Simple privacy-first dashboards; real-time. Minimalist GA alternative, event tracking, filters, custom dimensions, teams/projects', 'Analytics', 'freemium', 'low', 4.5, '', false),
  ('Coupler.io', 'couplerio', 'No-code data sync/visuals; 800+ source', 'No-code data sync/visuals; 800+ source. Automated data imports to Sheets/Looker/Power BI, scheduled refreshes, transformations, multi-source', 'Analytics', 'freemium', 'medium', 4.5, '', false),
  ('Flow Immersive', 'flow-immersive', 'AR/3D data viz; immersive web/XR', 'AR/3D data viz; immersive web/XR. 3D/AR visualizations, spatial data analysis, collaborative XR sessions for enterprise', 'Analytics', 'enterprise', 'medium', 4.5, '', false),
  ('Metrical', 'metrical', 'Lightweight real-time web metrics; simple startup', 'Lightweight real-time web metrics; simple startup. Real-time pageviews/events, goal tracking, custom properties, embed code, no complex', 'Analytics', 'free', 'low', 4.5, '', false)
